import {
    PopupModel
} from "../../../../../ui/__tests__/__mock__/model/popup";
const SELECTORS = {
    dialogMessage: "dx-dialog-message",
    cancelButton: '[aria-label="No"]'
};
export class ConfirmationDialogModel extends PopupModel {
    getMessage() {
        const overlay = this.getOverlayContent();
        const messageElement = overlay.querySelector(`.${SELECTORS.dialogMessage}`);
        return messageElement.textContent ?? ""
    }
    getCancelButton() {
        const element = this.getElement();
        return element.querySelector(SELECTORS.cancelButton)
    }
}
